// Merge gemma3 vision output back into page_blocks
const allPages = $('Check Confidence').first().json.all_pages;
const visionItems = $input.all();

// Build a map of page_num -> vision text
const visionMap = {};
for (const item of visionItems) {
  const pageNum = item.json.page_num;
  const visionText = item.json.choices?.[0]?.message?.content || '';
  visionMap[pageNum] = visionText;
}

// Replace low-confidence blocks with vision extraction
const mergedPages = allPages.map(page => {
  if (visionMap[page.page_num]) {
    return {
      ...page,
      blocks: [{
        block_type: 'text',
        text: visionMap[page.page_num],
        confidence: 0.88,
        source: 'gemma3_vision'
      }]
    };
  }
  return page;
});

return [{
  json: {
    all_pages: mergedPages,
    document_id: $('Webhook Trigger').first().json.document_id,
    tender_id: $('Webhook Trigger').first().json.tender_id,
    bidder_id: $('Webhook Trigger').first().json.bidder_id
  }
}];

// Pass pages straight through when all confidence >= 0.70
const data = $input.first().json;
return [{ json: data }];

// 1. Get Data from previous nodes
const webhookData = $('Webhook Trigger').first().json;
const wb = webhookData.body || webhookData; 
const ocrData = $('Docling OCR').first().json;

// 2. Map the flat page_blocks array
// Docling uses 'page_blocks' directly on the root object
const sourceBlocks = ocrData.page_blocks || [];

const allBlocks = sourceBlocks.map((block, index) => {
  return {
    block_id: `${ocrData.document_id || wb.document_id || 'doc'}-b${index}`,
    page_num: block.page_num || 1,
    block_type: block.block_type || 'text',
    text: block.text || '',
    confidence: block.confidence ?? 1.0,
    source: 'docling',
    bbox: block.bbox || null
  };
});

// 3. Assemble the Structured Document Object (SDO)
const sdo = {
  document_id: ocrData.document_id || wb.document_id || "unknown",
  tender_id: wb.tender_id || "unknown",
  bidder_id: wb.bidder_id || "unknown",
  filename: ocrData.filename || "unknown_file",
  file_type: wb.file_type || "png",
  total_pages: ocrData.num_pages || 1,
  total_blocks: allBlocks.length,
  blocks: allBlocks,
  ingestion_timestamp: new Date().toISOString(),
  input_hash: wb.input_hash || null,
  avg_confidence: ocrData.avg_confidence || null
};

return [{ json: sdo }];

// Get all items from the external nodes once at the start
const splitBlocksData = $('Split Blocks for Embedding').all();
const assembleSdoData = $('Assemble SDO').all(); // Added .all() to be safe

return $input.all().map((item, index) => {
  const pair = item.json;
  const vector = pair.data?.[0]?.embedding || [];

  if (!vector.length) {
    throw new Error(`Embedding vector is empty for item at index ${index}`);
  }

  function makeUUID() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
      const r = Math.random() * 16 | 0;
      return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
  }

  const blockId = makeUUID();

  // FIX HERE:
  // splitBlock changes per item (index 0, 1, 2...)
  const splitBlock = splitBlocksData[index]?.json || {};

  // assembleSdo stays the same for all items (always index 0)
  const assembleSdo = assembleSdoData[0]?.json || {}; 

  const qdrantUpsertPayload = {
    points: [
      {
        id: blockId,
        payload: {
          original_Blockid: splitBlock.block_id || '',
          document_id: assembleSdo.document_id || '',
          tender_id:   assembleSdo.tender_id   || '',
          bidder_id:   assembleSdo.bidder_id   || null,
          page_num:    splitBlock.page_num     || 0,
          block_type:  splitBlock.block_type   || 'text',
          text:        splitBlock.text         || '',
          confidence:  typeof splitBlock.confidence === 'number' ? splitBlock.confidence : 1.0,
          source:      splitBlock.source       || '',
        },
        vector: vector 
      }
    ]
  };

  return {
    json: {
      ...pair,
      block_id: blockId,
      qdrant_payload: qdrantUpsertPayload
    }
  };
});

// Map over every item that was sent to "Assemble SDO"
return $('Assemble SDO').all().map((documentItem) => {
  const docJson = documentItem.json;
  const blockItems = docJson.blocks || [];

  // Reconstruct page_blocks specifically for THIS document
  const page_blocks = blockItems.map((b, index) => {
    return {
      page_num:    b.page_num    ?? 1,
      block_index: index,
      block_type:  b.block_type  || 'text',
      text:        b.text        || '',
      confidence:  typeof b.confidence === 'number' ? b.confidence : 1.0,
      bbox:        Array.isArray(b.bbox) ? b.bbox : [],
      source:      b.source      || 'docling'
    };
  });

  // Compute avg_confidence for THIS document
  const avgConf = page_blocks.length > 0
    ? page_blocks.reduce((sum, b) => sum + b.confidence, 0) / page_blocks.length
    : 0;

  // Build the SDO for THIS document
  const sdo = {
    id:             docJson.document_id || '',
    tender_id:      docJson.tender_id   || '',
    bidder_id:      docJson.bidder_id   || '',
    filename:       docJson.filename    || '',
    file_type:      docJson.file_type   || '',
    num_pages:      docJson.total_pages  || 1,
    page_blocks:    page_blocks,
    avg_confidence: Math.round(avgConf * 10000) / 10000,
    ingested_at:    new Date().toISOString(),
    status:         'pending'
  };

  return { json: sdo };
});

// Map over every document found in Aggregate Results
return $('Aggregate Results').all().map(item => {
  const data = item.json;

  const payload = {
    tender_id:   data.tender_id || '',
    event_type:  'document_ingestion_complete',
    actor:       'n8n_wf1',
    entity_type: data.file_type || 'document',
    entity_id:   data.id || '', // Note: using 'id' from Aggregate Results
    detail:      `Ingestion complete for ${data.filename || 'unknown'}. Blocks: ${(data.page_blocks || []).length}. Avg confidence: ${data.avg_confidence ?? 'N/A'}. Ingested at: ${data.ingested_at || new Date().toISOString()}`
  };

  return { 
    json: { 
      audit_payload: JSON.stringify(payload) 
    } 
  };
});
